namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 100;

    private static readonly string[] Templates =
    [
        "Your build succeeded",
        "New comment on PR #42",
        "Deployment to staging complete",
        "Disk usage alert on server-3",
        "User signup: alice@example.com",
        "Nightly backup finished",
        "CI pipeline failed for main",
        "New release v2.4.1 published"
    ];

    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var now = DateTime.UtcNow;
        var initial = new List<Notification>
        {
            new() { Id = 1, Message = "Welcome to the notifications page!", Timestamp = now.AddMinutes(-10) },
            new() { Id = 2, Message = "System check passed", Timestamp = now.AddMinutes(-5) },
            new() { Id = 3, Message = "3 pending pull requests", Timestamp = now.AddMinutes(-1) },
        };
        return Task.FromResult(initial);
    }

    public Task<List<Notification>> CheckForNewNotificationsAsync()
    {
        // ~40% chance of a new notification each poll
        if (Random.Shared.Next(10) < 4)
        {
            var n = new Notification
            {
                Id = Interlocked.Increment(ref _nextId),
                Message = Templates[Random.Shared.Next(Templates.Length)],
                Timestamp = DateTime.UtcNow,
            };
            return Task.FromResult(new List<Notification> { n });
        }

        return Task.FromResult(new List<Notification>());
    }
}

