            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? _notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if state was NOT restored from prerender
        _notifications ??= await Svc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender,
            // so the polling loop only starts once the page is interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newer = await Svc.CheckForNewNotificationsAsync();
            if (newer.Count > 0)
            {
                _notifications ??= new();
                _notifications.InsertRange(0, newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

